import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

PSALMS = {
"9": {
"1": "<p><strong>ʾôdeh YHWH bĕkol-libbî</strong> (<em>ʾōḏeh YHWH bĕḵol-libbî</em>): 'I will praise the LORD with my whole heart.' The qal imperfect ʾôdeh (from yādâ, 'to praise/confess') expresses votive resolve. The superscription assigns the psalm to David and connects it to ʿal-mût labbēn — a phrase of uncertain meaning (possibly 'death of a son' or a melody title). The pairing of Psalms 9–10 as a single incomplete acrostic (the two share contiguous Hebrew letters ʾālep–kāp) suggests original unity; scribal or liturgical tradition divided them.</p>",
"2": "<p><strong>ʾeśmĕḥâ wĕʾeʿlōs bĕkā</strong> (<em>ʾeśmĕḥâ wĕʾeʿlōs bĕḵā</em>): 'I will be glad and exult in you.' Two cohortative forms — śāmaḥ (gladness) and ʿālas (exulting/leaping for joy) — express the emotional fullness of praise. The preposition bĕ- ('in you') grounds the joy in YHWH's person, not merely his acts. The phrase ʾăzammĕrâ šimkā 'elyôn, 'I will sing praises to your name, O Most High,' introduces the divine title ʿelyôn (Most High), associated with Melchizedek's blessing in Gen 14:18-20 and used especially in Psalms for YHWH's universal sovereignty.</p>",
"3": "<p><strong>bĕšûb ʾôyĕbay ʾāḥôr</strong> (<em>bĕšûḇ ʾōyĕḇay ʾāḥôr</em>): 'when my enemies turn back.' The infinitive construct bĕšûb introduces a temporal clause: the psalmist's praise is grounded in past experience of enemies' flight. The root kāšal ('stumble/fall') describes their collapse; yōbĕdû ('they perished') is a niphal perfect — passive voice capturing finality. The presence of YHWH is the cause: mippānêkā ('from before your face'), a recurring Psalter motif where the divine countenance both repels enemies and sustains the righteous.</p>",
"4": "<p><strong>kî ʿāśîtā mišpāṭî wĕdînî</strong> (<em>kî ʿāśîṯā mišpāṭî wĕḏînî</em>): 'for you have maintained my judgment and my cause.' The paired nouns mišpāṭ and dîn both designate legal vindication; together they constitute a hendiadys — 'my just cause.' The verb ʿāśâ is a perfect of completed action: YHWH has already acted as judge. The image of yāšabtā lĕkissēʾ, 'you sat down to the throne,' pictures YHWH enthroned as cosmic judge — language that anticipates the heavenly court scenes of Dan 7 and Rev 4–5.</p>",
"5": "<p><strong>gāʿartā gôyim ʾibbadtā rāšāʿ</strong> (<em>gāʿartā gôyim ʾibbadtā rāšāʿ</em>): 'you have rebuked the nations, destroyed the wicked.' The verb gāʿar ('rebuke with authority') is the same verb used in Ps 18:15 and Ps 106:9 for YHWH's rebuke of sea and nations — a term of theophanic power. Paired with ʾibbadtā (piel perfect of ʾābad, 'to cause to perish'), the two verbs are a tight synonymous parallel: rebuke leads to destruction. The blotting of the wicked man's name — šĕmām māḥîtā — echoes the covenant curse of obliterating remembrance (cf. Deut 9:14).</p>",
"6": "<p><strong>ḥorbôt tammû lānĕṣaḥ</strong> (<em>ḥorbôṯ tammû lānĕṣaḥ</em>): 'their ruins have come to a perpetual end.' The noun ḥorbôt (ruins, desolations) is plural and emphatic: entire cities reduced to waste. The phrase tammû lānĕṣaḥ — 'ended forever' — uses lānĕṣaḥ, a word meaning 'to perpetuity/to victory,' which in Psalms often signals eschatological finality. The enemy is addressed in second person in the Hebrew: 'O enemy — finished, ruins forever!' This apostrophe sharpens the rhetorical force of the vindication.</p>",
"7": "<p><strong>YHWH lĕʿôlām yēšēb</strong> (<em>YHWH lĕʿôlām yēšēḇ</em>): 'the LORD sits enthroned forever.' Against the transience of the wicked (v.6), YHWH's eternal session on the throne provides the structural antithesis. The verb yāšab ('sit/be enthroned') is used for royal stability; konnēn lammišpāṭ kissēʾô, 'he has established his throne for justice,' adds that the throne's purpose is mišpāṭ — not raw power but righteous governance. The phrase anticipates Ps 93–99, the enthronement psalms.</p>",
"8": "<p><strong>wĕhûʾ yišpōṭ-tēbēl bĕṣedeq</strong> (<em>wĕhûʾ yišpōṭ-tēḇēl bĕṣeḏeq</em>): 'and he will judge the world in righteousness.' The noun tēbēl ('world, inhabited earth') expands the scope beyond Israel to the entire populated world. The prepositional pair bĕṣedeq and bĕmêšārîm ('in righteousness / in uprightness') function as ethical instruments: YHWH's judgment is characterized by covenant fidelity and impartial equity. This verse is a seed of the NT vision of Christ judging the world 'in righteousness' (Acts 17:31).</p>",
"9": "<p><strong>wîhî YHWH miśgāb laddāk</strong> (<em>waYHWH miśgāḇ laddāḵ</em>): 'and the LORD is a high refuge for the oppressed.' The noun miśgāb ('high fortress, stronghold') comes from śāgab ('to be high/inaccessible'); YHWH himself is the elevated place to which the poor flee. The rare noun dāk ('crushed one, oppressed') points to those who have been ground down by the wicked — the same social group the preceding verses described the wicked exploiting. The verb yihyeh (imperfect) indicates ongoing, present-tense provision: not a one-time rescue but a permanent refuge.</p>",
"10": "<p><strong>wĕyibṭĕḥû bĕkā yôdĕʿê šĕmekā</strong> (<em>wĕyiḇṭĕḥû ḇĕḵā yôḏĕʿê šĕmeḵā</em>): 'and those who know your name trust in you.' The verb bāṭaḥ ('trust, rely upon') in the qal expresses confident, settled reliance — not merely intellectual belief. The qualifier yôdĕʿê šĕmekā, 'those who know your name,' is covenant language: knowing the name in the OT means experiencing YHWH's revealed character (Exod 3:14-15; 6:3). The result: kî lōʾ-ʿāzabtā dōrĕšêkā YHWH, 'for you have not forsaken those who seek you' — a theological anchor for unanswered prayer: seeking is never in vain.</p>",
"11": "<p><strong>zammĕrû laYHWH yōšēb ṣiyyôn</strong> (<em>zammĕrû laYHWH yōšēḇ ṣiyyôn</em>): 'sing praises to the LORD who dwells in Zion.' The piel imperative zammĕrû ('make music, sing') summons communal praise. The designation yōšēb ṣiyyôn, 'the one who dwells in Zion,' grounds YHWH's cosmic throne (v.7) in a specific earthly locus — Zion/Jerusalem as the place where heaven and earth meet. The second half, haggîdû bāʿammîm ʿălîlôtāyw, 'declare his deeds among the peoples,' extends the witness of praise to the nations — a missionary impulse within the Psalter.</p>",
"12": "<p><strong>kî dōrēš dāmîm ʾôtām zākar</strong> (<em>kî dōrēš dāmîm ʾôṯām zāḵar</em>): 'for he who avenges blood remembers them.' The participle dōrēš dāmîm ('one who investigates/requires blood') draws on the legal language of blood-vengeance: YHWH as the one who holds killers accountable. The phrase lōʾ šākaḥ ṣaʿaqat ʿănāwîm, 'he does not forget the cry of the afflicted,' creates an inclusio with v.9: the oppressed who flee to YHWH are never outside his attention. The noun ʿănāwîm ('afflicted, poor, humble') is a key Psalter term for those who trust wholly in YHWH (cf. Ps 22:26; 37:11; Matt 5:5).</p>",
"13": "<p><strong>ḥonnēnî YHWH rĕʾēh ʿonî mēśonĕʾay</strong> (<em>ḥonnēnî YHWH rĕʾēh ʿonî mēśônĕʾāy</em>): 'Be gracious to me, O LORD; see my affliction by those who hate me.' The qal imperative ḥonnēnî invokes the ḥānan root (grace, favor), used of the unmerited favor of a superior to an inferior. The verb rĕʾēh ('see/observe') is a plea for divine attention — the counterpart to lōʾ šākaḥ in v.12. The phrase mǎrômmî miššaʿărê māwet, 'you who lift me from the gates of death,' introduces the gates of death (Sheol's threshold) as the extremity from which YHWH rescues.</p>",
"14": "<p><strong>lĕmaʿan ʾăsappĕrâ kol-tĕhillātekā</strong> (<em>lĕmaʿan ʾăsappĕrâ ḵol-tĕhillāṯeḵā</em>): 'that I may declare all your praise.' The purpose clause with the cohortative ʾăsappĕrâ ('I will tell/recount') shows that deliverance is not merely personal relief but has a doxological telos — it creates testimony. The setting is bĕšaʿărê bat-ṣiyyôn, 'in the gates of the daughter of Zion,' i.e., at the city gate where public life and worship converged. The pledge to praise publicly in the assembly is a votive form common in Psalter laments (cf. Ps 22:22, 25).</p>",
"15": "<p><strong>ṭāb'û gôyim bĕšaḥat ʿāśû</strong> (<em>ṭāḇĕʿû gôyim bĕšaḥaṯ ʿāśû</em>): 'the nations have sunk in the pit they made.' The verb ṭābaʿ ('sink, be submerged') is used of sinking in mud or deep waters; applied to nations, it vivifies their sudden collapse. The theological principle is lex talionis retributive justice: bāreŝet zû ṭāmānû nilkĕdâ raglām, 'in the net they hid, their own foot has been caught.' This principle — the wicked falling into their own traps — appears throughout the Psalter (cf. Ps 7:15-16; 35:8) and grounds confidence in ultimate justice.</p>",
"16": "<p><strong>nôdaʿ YHWH mišpāṭ ʿāśâ</strong> (<em>nôḏaʿ YHWH mišpāṭ ʿāśâ</em>): 'the LORD has made himself known; he has executed judgment.' The niphal nôdaʿ ('he was made known') means that YHWH's nature is revealed through his acts of judgment — theodicy is also theology. The phrase bĕpōʿal yādāyw nôqēš rāšāʿ, 'the wicked is snared in the work of his own hands,' echoes v.15: the trap-maker becomes the trapped. The enigmatic annotation Higgaion Selah may indicate a meditative musical interlude, inviting reflection on this reversal.</p>",
"17": "<p><strong>yāšûbû rĕšāʿîm lišĕʾôl</strong> (<em>yāšûḇû rĕšāʿîm lišĕʾôl</em>): 'the wicked shall return to Sheol.' The verb šûb ('return, go back') implies that Sheol is the wicked's natural origin or destination — dust to dust, darkness to darkness. The phrase kol-gôyim šĕkēḥê ʾĕlōhîm, 'all the nations that forget God,' extends the verdict beyond Israel to gentile nations who suppress the knowledge of God (cf. Rom 1:21). This verse forms the negative counterpart to v.10 — those who know the name trust; those who forget God perish.</p>",
"18": "<p><strong>kî lōʾ lānĕṣaḥ yiššākēaḥ ʾebyôn</strong> (<em>kî lōʾ lānĕṣaḥ yiššāḵēaḥ ʾeḇyôn</em>): 'for the needy shall not always be forgotten.' The word ʾebyôn ('poor, destitute') denotes material poverty and, in the Psalter's theology, those who depend entirely on YHWH for survival. The phrase lōʾ lānĕṣaḥ yiššākēaḥ is emphatically negated: the forgetting is not permanent. The second half, tiqwat ʿănāwîm tōʾbad lāʿad, 'the hope of the afflicted shall not perish forever,' uses ʾeḇed ('perish') — the same verb used for the wicked's destruction in v.3 — now negated for the righteous. Hope is imperishable.</p>",
"19": "<p><strong>qûmâ YHWH ʾal-yĕʿōz ʾĕnôš</strong> (<em>qûmâ YHWH ʾal-yĕʿōz ʾĕnôš</em>): 'Arise, O LORD; let not man prevail.' The imperative qûmâ ('arise!') is a liturgical summons to divine action, common in Psalter prayers (cf. Ps 7:6; 44:26; 74:22). The noun ʾĕnôš ('mortal man' — from the root implying frailty/sickness) emphasizes human finitude: it is absurd for frail humans to triumph over the eternal God. The phrase yiššāpĕṭû gôyim ʿal-pānêkā, 'let the nations be judged before you,' repeats the court language of v.4-8 — the psalm ends where it began, in the courtroom of heaven.</p>",
"20": "<p><strong>šîtâ YHWH môrâ lāhem</strong> (<em>šîṯâ YHWH môrâ lāhem</em>): 'Put them in fear, O LORD.' The noun môrâ (from yārēʾ, 'to fear') connotes the dread that falls on enemies when God acts. The phrase yēdĕʿû gôyim ʾĕnôš hēmmâ, 'let the nations know that they are but men,' is the psalm's culminating reversal: those who thought themselves lords of history (v.4-6) are exposed as ʾĕnôš — mortal, contingent, creature. The Selah punctuates the closing appeal for all humanity to recognize creatureliness before the creator.</p>"
},
"10": {
"1": "<p><strong>lāmmâ YHWH taʿămōd bĕrāḥôq</strong> (<em>lāmmâ YHWH taʿămōḏ bĕrāḥôq</em>): 'Why, O LORD, do you stand far off?' The acrostic continues from Psalm 9 (together covering ʾālep through kāp), though Psalm 10 lacks an explicit superscription in Hebrew — further evidence of original unity. The question lāmmâ ('why?') opens a lament of divine hiddenness: God's standing bĕrāḥôq ('at a distance') and hiding bĕʿittôt bĕṣārâ ('in times of trouble') contradicts the refuge he is declared to be in 9:9. The tension is deliberate: the psalmist prays out of experienced abandonment toward known theology.</p>",
"2": "<p><strong>bĕgaʾăwat rāšāʿ yiddalaqu ʿānî</strong> (<em>bĕḡaʾăwaṯ rāšāʿ yiddalaqu ʿānî</em>): 'in arrogance the wicked pursues the poor.' The verb dālaq ('pursue hotly, burn after') describes predatory intensity. The noun gaʾăwâ ('pride, arrogance') is the root evil: the wicked man's self-elevation drives his exploitation. The passive/reflexive prayer yitkĕṭĕšû bĕmaḥšĕbôt zû ḥāšābû, 'let them be caught in the schemes they have devised,' echoes the lex talionis principle established in ch.9 — the trap-set becomes the trap-caught.</p>",
"3": "<p><strong>kî hillēl rāšāʿ ʿal-taʾăwat napšô</strong> (<em>kî hillēl rāšāʿ ʿal-taʾăwaṯ napšô</em>): 'for the wicked praises himself for the desire of his soul.' The piel hillēl ('to praise, boast') — root of hallĕlûyāh — is here inverted: the wicked praises himself rather than YHWH, treating his own desires as ultimate. The phrase ûbōṣēaʿ bērēk niʾēṣ YHWH, 'and the one who grasps for gain blesses himself but despises the LORD,' displays the theological corruption of covetousness: greed simultaneously demands self-blessing and despises God. The noun bōṣēaʿ ('one who cuts off/gains by violence') implies criminal acquisition.</p>",
"4": "<p><strong>rāšāʿ kĕgōbah ʾappô bal-yidrōš</strong> (<em>rāšāʿ kĕḡōḇah ʾappô ḇal-yiḏrōš</em>): 'the wicked, in his haughtiness, does not seek.' The phrase ʾên ʾĕlōhîm kol-mĕzimmôtāyw, 'there is no God in all his schemes,' is not theoretical atheism but practical atheism: the wicked operates as though God neither sees nor judges. The noun mĕzimmôt ('plans, schemes') is morally neutral in itself but here describes a mind from which God has been systematically excluded. Paul draws on vv.7 and 14 (LXX: Pss 9–10 were one psalm in LXX) in his catena of universal sinfulness in Rom 3:10-18.</p>",
"5": "<p><strong>yāḥîlû dĕrākāyw bĕkol-ʿēt</strong> (<em>yāḥîlû dĕrāḵāyw bĕḵol-ʿēṯ</em>): 'his ways prosper at all times.' The hiphil yāḥîlû (from ḥûl, 'twist/writhe/succeed') may mean 'his ways are firm/stable.' The apparent prosperity of the wicked is the classic theodicy problem (cf. Ps 73). The phrase mārôm mišpāṭêkā miggĕdô, 'your judgments are on high, out of his sight,' means the wicked cannot perceive divine governance — his immediate success blinds him. He puffs contempt at his enemies: yāpîaḥ bāhem, 'he blows at them,' an image of arrogant dismissal.</p>",
"6": "<p><strong>ʾāmar bĕlibbô bal-ʾemmôṭ</strong> (<em>ʾāmar bĕlibbô ḇal-ʾemôṭ</em>): 'he said in his heart, 'I shall not be moved.'' The inner speech ʾāmar bĕlibbô ('he said in his heart') introduces the wicked man's self-deception. The boast bal-ʾemmôṭ lĕdōr wādōr ʾăšer lōʾ bĕrāʿ, 'I shall not be moved; throughout all generations I shall not meet adversity,' is a counterfeit of YHWH's own eternal stability (9:7). The wicked imitates divine permanence — precisely the Edenic temptation (Gen 3:5: 'you will be like God').</p>",
"7": "<p><strong>ʾālâ pîhû māʾēn ûmirmâ</strong> (<em>ʾālâh pîhû māʾēn ûmirmâ</em>): 'his mouth is full of cursing and deceit and oppression.' The noun ʾālâ ('oath, curse') refers to invoking divine curses against others; mirmâ is 'treachery/deceit'; tōk is 'oppression/fraud.' Three words capture the weaponization of speech. Paul cites a version of this verse in Rom 3:14 ('their mouth is full of cursing and bitterness') as evidence of universal sinfulness — a NT appropriation of what the psalmist observed in a specific oppressor to diagnose a universal human condition.</p>",
"8": "<p><strong>yēšēb bĕmaʾărab ḥăṣērîm</strong> (<em>yēšēḇ bĕmaʾĂraḇ ḥăṣērîm</em>): 'he sits in ambush in the villages.' The noun maʾărab ('ambush') describes premeditated predation; ḥăṣēr ('village, courtyard') is where the vulnerable live. The imagery intensifies: the wicked hides bĕmistārîm ('in hiding places') to murder nāqî, 'the innocent.' His eyes secretly watch (bĕmistārîm yeṣappĕnû ʿênāyw) for the helpless — surveillance used for predation rather than protection.</p>",
"9": "<p><strong>yeʾĕrōb bammistār kĕʾaryēh bĕsukkô</strong> (<em>yeʾĕrōḇ ḇammistār kĕʾaryēh bĕsukkô</em>): 'he lies in wait in secret like a lion in its den.' The lion simile (kĕʾaryēh) is the Psalter's stock image for a predator who stalks rather than fights openly. The victim is ʿānî ('the poor/afflicted'), the same social group the psalm defends. The verb yimšōk ('he drags/draws away') — used of dragging a net catch — captures the violent, irreversible nature of the oppression. The poor man is prey.</p>",
"10": "<p><strong>yiddakkeh yāšōaḥ wĕnāpal</strong> (<em>yiddakkeh yāšōaḥ wĕnāpal</em>): 'he crouches, he stoops, and the poor man falls.' The sequence of three verbs — yiddakkeh (crushed down), yāšōaḥ (stoops), nāpal (falls) — creates a cinematic slow-motion of the predator's approach and the victim's collapse. The phrase bĕḥēlĕkāyw ḥêlekā ʿăniyyîm, 'by his mighty ones the poor are crushed,' suggests the wicked man's network of power — he does not act alone but commands enforcers.</p>",
"11": "<p><strong>ʾāmar bĕlibbô šākaḥ ʾēl</strong> (<em>ʾāmar bĕlibbô šākaḥ ʾēl</em>): 'he says in his heart, 'God has forgotten.'' The second inner monologue (cf. v.6) deepens the portrait of practical atheism: hissātîr pānāyw lōʾ-rāʾâ lānĕṣaḥ, 'he has hidden his face, he will never see.' The triple claim — God forgets, God hides, God never sees — mirrors an inversion of the divine assurances in Ps 9:12-13 (God remembers, God sees). The psalmist is not endorsing this view; he quotes the wicked to expose their delusion before calling on God to disprove it.</p>",
"12": "<p><strong>qûmâ YHWH ʾēl nĕśēʾ yādekā</strong> (<em>qûmâ YHWH ʾēl nĕśēʾ yāḏeḵā</em>): 'Arise, O LORD! O God, lift up your hand!' The liturgical imperative qûmâ returns from 9:19 — the lament section ends and the petition begins. The phrase ʾal-tiškaḥ ʿănāwîm, 'do not forget the afflicted,' directly refutes the wicked man's claim in v.11 (God has forgotten). The psalmist's prayer strategically uses the enemy's own language against him: if the wicked says 'God forgets,' the psalmist replies by praying 'do not forget.'</p>",
"13": "<p><strong>ʿal-mah niʾēṣ rāšāʿ ʾĕlōhîm</strong> (<em>ʿal-mah niʾēṣ rāšāʿ ʾĕlōhîm</em>): 'Why does the wicked despise God?' The niph'al niʾēṣ ('despise, treat with contempt') addresses divine honor at stake: YHWH's failure to act is the wicked man's theodicy in reverse — his impunity 'proves' God doesn't care. The wicked claims lōʾ tidrōš, 'you will not call to account,' treating divine patience as permanent indifference. The psalmist's complaint is partly apologetic: YHWH's honor requires that he vindicate the poor and disprove the wicked's theology.</p>",
"14": "<p><strong>rāʾîtâ kî-ʾattâ ʿāmāl wākaʿas tabbîṭ</strong> (<em>rāʾîṯā ḵî-ʾattâ ʿāmāl wāḵaʿas tabbîṭ</em>): 'You do see, for you observe trouble and vexation.' Against the wicked man's claim that God neither sees nor acts (v.11), the psalmist asserts rāʾîtâ — 'you have seen.' The infinitive lātet bĕyādekā, 'to give into your hand,' frames justice as a divine responsibility: the oppressed 'commits himself' (yaʿăzōb) to YHWH, and the fatherless (yātôm) finds his helper. The polarity of blindness (v.11) and sight (v.14) structures the entire psalm's theodicy.</p>",
"15": "<p><strong>šĕbōr zĕrôaʿ rāšāʿ wārāʿ</strong> (<em>šĕḇôr zĕrôaʿ rāšāʿ wārāʿ</em>): 'Break the arm of the wicked and evildoer.' The qal imperative šĕbōr ('break!') calls for decisive intervention: the arm (zĕrôaʿ) represents power — to break it is to disarm the oppressor. The phrase tidrōš rišʿô bĕl-timṣāʾ, 'seek out his wickedness until you find none,' envisions complete justice — not merely punishment but the full unraveling of wickedness until nothing remains. This is eschatological hope within an historical prayer.</p>",
"16": "<p><strong>YHWH melek ʿôlām wāʿed</strong> (<em>YHWH melek ʿôlām wāʿeḏ</em>): 'The LORD is king forever and ever.' The declaration of divine kingship (melek) forms the climax after the appeals: YHWH answers not as a distant judge but as a king whose rule is ʿôlām wāʿed ('age upon age'). The noun gôyim ('nations') appears again — āḇĕdû gôyim mēʾarṣô, 'the nations have perished from his land' — but now as past-tense historical fulfillment, not just eschatological hope. YHWH's land-claim has expelled the wicked.</p>",
"17": "<p><strong>tawat ʿănāwîm šāmaʿtâ YHWH</strong> (<em>taʾăwaṯ ʿănāwîm šāmaʿtâ YHWH</em>): 'The desire of the afflicted you have heard, O LORD.' The perfect šāmaʿtâ is a perfect of confidence: the psalmist speaks of future hearing as certain fact. The verb tākîn libbām ('you will establish their heart') suggests that divine attention strengthens the inner resolve of the afflicted — hearing transforms not just circumstances but persons. The outcome taqšîb ʾoznekā, 'you will incline your ear,' emphasizes receptive divine posture.</p>",
"18": "<p><strong>lišpōṭ yātôm wādāk</strong> (<em>lišpōṭ yātôm wādāk</em>): 'to do justice to the fatherless and the oppressed.' The infinitive lišpōṭ summarizes YHWH's purpose: to judge/vindicate. The pair yātôm wādāk ('fatherless and crushed') represent the most vulnerable — those with no human advocate. The final phrase bal-yôsip ʿôd laʿărōṣ ʾĕnôš min-hāʾāreṣ, 'that man of earth may strike terror no more,' returns to the ʾĕnôš ('mortal') of 9:20: the psalm's closing vision is the end of human tyranny before divine sovereignty. The earthly oppressor — whatever his momentary power — is finally, irreversibly exposed as merely mortal.</p>"
},
"11": {
"1": "<p><strong>baYHWH ḥāsîtî</strong> (<em>ḇaYHWH ḥāsîṯî</em>): 'In the LORD I take refuge.' The opening confession — baYHWH ḥāsîtî — is the psalm's thesis. The root ḥāsâ ('to take refuge, flee for protection') is used extensively in the Psalter for covenant trust; it implies running to a physically stronger protector. The advice of unnamed advisors (ʾîmrû lĕnapšî nûdî harkĕm ṣippōrĕkem, 'flee like a bird to your mountain!') is rejected before it is quoted. The psalm's genre has been called a 'confidence psalm' — the trust expressed in v.1 needs no argument; it is the starting point from which everything else follows.</p>",
"2": "<p><strong>kî hinnēh rĕšāʿîm yidrekûn qešet</strong> (<em>kî hinnēh rĕšāʿîm yiḏreḵûn qāšeṯ</em>): 'for behold, the wicked bend the bow.' The verb dārak ('to tread/bend') applied to the bow describes arming for attack. The imagery of arrow shot bĕmô-ʾōpel, 'in the dark,' emphasizes treachery — the attack is hidden, impossible to defend against. The target is lĕyišrê-lēb, 'at the upright in heart.' The contrast — wicked with weapons / righteous with no defence — creates the crisis that makes the question of v.3 so pressing.</p>",
"3": "<p><strong>kî hāšĕtôt yehāressûn mah-pāʿal ṣaddîq</strong> (<em>kî hāšŝtôṯ yehārēsûn mah-pāʿal ṣaddîq</em>): 'when the foundations are destroyed, what can the righteous do?' The noun šātôt ('foundations, pillars') — from šît, 'to set, establish' — refers to the moral and social structures that make ordered life possible. The rhetorical question mah-pāʿal ṣaddîq? ('what can the righteous do?') is the voice of despair: if the foundations collapse, no human action suffices. The psalm's answer is implicit: what the righteous do is precisely what v.1 declares — take refuge in YHWH, the one on whose throne the foundations ultimately rest.</p>",
"4": "<p><strong>YHWH bĕhêkal qodšô YHWH baššāmayim kissĕʾô</strong> (<em>YHWH bĕhêḵal qodšô YHWH baššāmayim kissĕʾô</em>): 'The LORD is in his holy temple; the LORD — his throne is in heaven.' The two-fold affirmation — earthly temple and heavenly throne — is programmatic: YHWH simultaneously inhabits the Jerusalem sanctuary (locus of covenant presence) and the heavenly court (locus of sovereign judgment). The participle bōḥēn ('he tests/examines') combined with ʿênāyw yĕḥĕzû ('his eyes see') directly answers the wicked man's claim in Ps 10:11 that God neither sees nor acts. Divine omniscience is the foundation that the wicked man's practical atheism cannot survive.</p>",
"5": "<p><strong>YHWH ṣaddîq yibḥān wĕrāšāʿ wĕʾōhēb ḥāmās śānĕʾâh napšô</strong> (<em>YHWH ṣaddîq yiḇḥān wĕrāšāʿ wĕʾōhēḇ ḥāmās śānĕʾāh napšô</em>): 'The LORD tests the righteous, but the wicked and the one who loves violence his soul hates.' The verb bāḥan ('test, examine, refine') — used of metallic refinement — indicates that YHWH's scrutiny of the righteous is purifying, not merely punitive. The phrase napšô śānĕʾâh ('his soul hates') applied to the wicked is strong: divine hate is not emotional pique but settled moral revulsion at evil. The 'one who loves violence' (ʾōhēb ḥāmās) identifies the wicked by affection rather than merely behavior.</p>",
"6": "<p><strong>yamṭēr ʿal rĕšāʿîm paḥîm</strong> (<em>yamṭēr ʿal-rĕšāʿîm paḥîm</em>): 'he rains snares on the wicked.' The divine judgment is pictured as a storm of paḥîm ('snares, traps'), ʾēš ('fire'), wĕgāprit ('brimstone'), and rûaḥ zîlĕʿôt ('a scorching wind'). The sulfur-and-fire imagery recalls Sodom (Gen 19:24) — the paradigmatic judgment on cities that exchanged hospitality and justice for violence. The phrase zōt mĕnat kôsām, 'this is the portion of their cup,' uses kôs ('cup') as a metonym for fate or divine allotment — the wicked receive what their choices earned.</p>",
"7": "<p><strong>kî ṣaddîq YHWH ṣĕdāqôt ʾāhēb</strong> (<em>kî ṣaddîq YHWH ṣĕdāqôt ʾāhēḇ</em>): 'for the LORD is righteous; he loves righteous deeds.' The final verse resolves the crisis of v.3: because YHWH himself is ṣaddîq ('righteous'), he necessarily loves ṣĕdāqôt ('acts of righteousness'). The wicked foundations (v.3) cannot finally stand because righteousness is ontologically grounded in YHWH's character. The concluding phrase yāšār yĕḥĕzû pānêmô, 'the upright shall behold his face,' is the psalm's beatific vision — the reward of those who flee to YHWH (v.1) is intimacy with him, seeing the face that the wicked cannot bear (cf. Rev 22:4; Matt 5:8).</p>"
},
"12": {
"1": "<p><strong>hôšîʿâ YHWH kî gāmar ḥāsîd</strong> (<em>hôšîʿâ YHWH kî gāmar ḥāsîd</em>): 'Save, O LORD, for the godly man ceases.' The qal perfect gāmar ('to come to an end, cease') describes the ḥāsîd ('covenant-loyal one, godly person') as nearly extinct. The word ḥāsîd (from ḥesed, 'steadfast love') denotes one who embodies covenant faithfulness. Its near-disappearance signals covenantal crisis. The companion phrase kî passû ʾĕmûnîm mibbĕnê hāʾādām, 'for the faithful have vanished from among the children of man,' uses ʾĕmûnîm ('faithful ones') — those whose lives are characterized by ʾĕmûnâ (faithfulness/reliability).</p>",
"2": "<p><strong>šāwĕʾ yĕdabbĕrû ʾîš ʾet rēʿēhû</strong> (<em>šāwĕʾ yĕdabbĕrû ʾîš ʾeṯ-rēʿēhû</em>): 'Each speaks falsehood to his neighbor.' The noun šāwĕʾ ('vanity, falsehood, emptiness') describes speech that has no correspondence to reality. The phrase śĕpat ḥălāqôt bĕlēb wālēb yĕdabbĕrû, 'with flattering lips and a double heart they speak,' introduces bĕlēb wālēb ('with a double heart' — literally 'with heart and heart'). The doubled lēb signals divided loyalty: the speaker's external words do not match the internal reality. This linguistic duplicity is the social crisis the psalm laments.</p>",
"3": "<p><strong>yakrēt YHWH kol-śiptê ḥălāqôt</strong> (<em>yaḵrēt YHWH kol-śipĕtê ḥălāqôṯ</em>): 'May the LORD cut off all flattering lips.' The hiphil jussive yakrēt ('may he cut off') moves from description to petition. The hendiadys śiptê ḥălāqôt wĕlāšôn mĕdabberet gĕdōlôt, 'flattering lips and the tongue that speaks great things,' pairs the instrument (lips/tongue) with the content (great boasts/grand arrogance). The contrast between the godly who have ceased (v.1) and these boasters who dominate drives the prayer for reversal.</p>",
"4": "<p><strong>ʾăšer ʾāmĕrû lĕlāšōnēnû nagbîr</strong> (<em>ʾăšer ʾāmĕrû lĕlāšōnēnû naḡḇîr</em>): 'who have said, 'With our tongue we will prevail.'' The hiphil nagbîr ('we will be strong, prevail') — from gābar ('to be mighty') — claims that rhetorical power is sovereign. The phrase śĕpātênû ʾittānû, 'our lips are our own/with us,' asserts linguistic autonomy: speech is self-owned, accountable to no one. The closing question mî ʾādôn lānû, 'who is lord over us?', is the boast's logical conclusion and the psalm's central theological problem: the rejection of any authority beyond the self.</p>",
"5": "<p><strong>mišōd ʿăniyyîm mēʾanqat ʾebyônîm</strong> (<em>mišōḏ ʿăniyyîm mēʾanqaṯ ʾeḇyônîm</em>): 'Because of the devastation of the poor, because of the groaning of the needy.' The noun šōd ('devastation, destruction') describes violent oppression; ʾanqâ ('groaning') is the sound of extremity. YHWH's response is direct speech: ʿattâ ʾāqûm yōʾmar YHWH, 'now I will arise, says the LORD.' The divine yōʾmar ('says the LORD') — an oracle formula — gives the next words prophetic authority: ʾāšît bĕyēšaʿ yāpîaḥ lô, 'I will place in safety the one who pants/longs for it.' The verb yāpîaḥ ('to breathe heavily, pant') captures the desperate longing of the oppressed.</p>",
"6": "<p><strong>ʾimrôt YHWH ʾimrôt tĕhōrôt</strong> (<em>ʾimrôt YHWH ʾimrôt ṭĕhōrôṯ</em>): 'The words of the LORD are pure words.' The repetition ʾimrôt ... ʾimrôt ('words ... words') is emphatic: this is definitional. The adjective tāhôr ('pure, clean') is the technical term for cultic purity — what is unadulterated, without contamination. The simile kesep ṣārûp bĕʿalîl lāʾāreṣ mĕzuqqāq šibʿātayim, 'silver refined in a furnace on the ground, purified seven times,' specifies the purity: smelted and resmelted until all dross is gone. In context this is a pointed contrast to the hollow words of v.2-4 — human speech is śāwĕʾ ('vain'); divine speech is tāhôr.</p>",
"7": "<p><strong>ʾattâ YHWH tišmĕrēm</strong> (<em>ʾattâ YHWH tišmĕrēm</em>): 'You, O LORD, will keep them.' The subject ʾattâ ('you') is emphatic — against all human protectors who have failed, YHWH is the one who guards. The referent of tišmĕrēm is debated: the 'them' may refer to 'the poor' of v.5 or 'the words' of v.6. Both yield coherent sense. The phrase tiṣṣĕrennû min-haddôr zû lĕʿôlām, 'you will guard us from this generation forever,' shifts to first person — the psalmist includes himself and the community among those preserved. The phrase min-haddôr zû ('from this generation') indicates the corrupt contemporaries of vv.1-4.</p>",
"8": "<p><strong>sābîb rĕšāʿîm yithallākûn</strong> (<em>sāḇîḇ rĕšāʿîm yiṯhallāḵûn</em>): 'The wicked walk about on every side.' The hitpael yithallākûn ('walk back and forth') suggests restless movement of the wicked who dominate the landscape. The phrase kĕrum zullût libnê ʾādām, 'when what is vile is exalted among the children of man,' names the inversion: zullût ('vileness, baseness') rises to prominence. The psalm ends not with resolution but with honest observation — the present moment is bleak. Faith in YHWH's word (v.6) and his guardianship (v.7) does not eliminate the experience of living in a corrupt generation.</p>"
},
"13": {
"1": "<p><strong>ʿad-ʾānâ YHWH tišĕkāḥēnî nĕṣaḥ</strong> (<em>ʿaḏ-ʾānâ YHWH tišĕḵāḥēnî nĕṣaḥ</em>): 'How long, O LORD? Will you forget me forever?' The double question ʿad-ʾānâ / ʿad-ʾānâ ('how long / how long') opens Psalm 13 in anaphora — the same opening repeats in vv.1-2 a total of four times, creating a rhetorical escalation of anguish. The verb šākaḥ ('forget') is the same verb the wicked apply to God in Ps 10:11; here the psalmist fears it may be true of himself. The adverb nĕṣaḥ ('forever, to perpetuity') intensifies: will the abandonment never end? This is honest lament theology — the question is addressed to God, not denied.</p>",
"2": "<p><strong>ʿad-ʾānâ ʾāśît ʿēṣôt bĕnapšî</strong> (<em>ʿaḏ-ʾānâ ʾāśîṯ ʿēṣôṯ ḇĕnapšî</em>): 'How long must I take counsel in my soul?' The four 'how long' questions span two verses: (1) divine forgetting, (2) divine hiding, (3) internal anguish ('counsel in my soul'), (4) enemy triumph. The noun ʿēṣôt ('counsel, plans') combined with yāgôn bĕlibî, 'sorrow in my heart,' shows the psalmist at an inner limit — exhausted by trying to think his way through the crisis. The rise of the enemy — yārûm ʾôyĕbî ʿālay ('my enemy is exalted over me') — is the external dimension of the same abandonment.</p>",
"3": "<p><strong>habbîṭâ ʿănēnî YHWH ʾĕlōhāy</strong> (<em>habbîṭâ ʿănēnî YHWH ʾĕlōhāy</em>): 'Consider and answer me, O LORD my God.' The three imperatives — habbîṭâ ('look!'), ʿănēnî ('answer me!'), hāʾîrâ ʿênay ('light up my eyes!') — are the psalm's petition block. The phrase pen-ʾîšan hammāwet, 'lest I sleep the death sleep,' uses sleep as a euphemism for death; the dimming of eyes in death is contrasted with the eyes 'lit up' by divine attention. The possessive ʾĕlōhāy ('my God') is intimate — even in the darkest lament, the covenant relationship is assumed.</p>",
"4": "<p><strong>pen-yōʾmar ʾôyĕbî yĕkoltîw</strong> (<em>pen-yōʾmar ʾôyĕbî yĕḵoltîw</em>): 'lest my enemy say, 'I have prevailed over him.'' The psalmist's concern is not merely personal survival but the theological stakes: if he falls, the enemy's gloating — yāgîlû ṣārāyw kî ʾemmôṭ, 'his adversaries rejoice when I am moved' — will be a public refutation of trust in YHWH. The logic is the same as Moses' appeal to YHWH's reputation in Exod 32:12 and Num 14:13-16: the outcome of the psalmist's situation reflects on the credibility of YHWH's protection.</p>",
"5": "<p><strong>waʾănî bĕḥasdĕkā bāṭaḥtî</strong> (<em>waʾănî ḇĕḥasdĕḵā ḇāṭaḥtî</em>): 'But I have trusted in your steadfast love.' The waw-adversative waʾănî ('but as for me') marks the psalm's dramatic turn: from lament (vv.1-2) and petition (vv.3-4) to trust and praise (vv.5-6). The perfect bāṭaḥtî ('I have trusted') indicates an established disposition — not a new resolution but a prior settled stance. The noun ḥesed ('steadfast love, covenant loyalty') is YHWH's defining character; to trust in it is to rest on the most reliable foundation available. The result: yāgēl libbî bîšûʿātekā, 'my heart shall rejoice in your salvation.'</p>",
"6": "<p><strong>ʾāšîrâ laYHWH kî gāmal ʿālay</strong> (<em>ʾāšîrâ laYHWH kî ḡāmal ʿālay</em>): 'I will sing to the LORD, because he has dealt bountifully with me.' The cohortative ʾāšîrâ ('I will sing!') resolves the psalm with a vow of praise. The verb gāmal ('to deal with, requite, complete') — in the qal, 'to wean, to fully develop' — here means 'to deal bountifully, to complete one's care for.' The phrase kî gāmal ʿālay projects completed deliverance from the perspective of trust: the psalmist sings before the rescue arrives, confident it will come. This gap between petition and answered prayer is bridged by ḥesed-trust, making Psalm 13 a template for faith under unanswered prayer.</p>"
},
"14": {
"1": "<p><strong>ʾāmar nābāl bĕlibbô ʾên ʾĕlōhîm</strong> (<em>ʾāmar nāḇāl bĕlibbô ʾên ʾĕlōhîm</em>): 'The fool says in his heart, 'There is no God.'' The noun nābāl ('fool') in Hebrew does not primarily denote intellectual deficiency but moral and relational failure — the nābāl is one who is morally obtuse, living without reference to God or covenant. The phrase bĕlibbô ('in his heart') again signals practical atheism: the claim is not philosophical but operational. The result: hišḥîtû hiṭʿîbû ʿălîlâ, 'they are corrupt, they do abominable works' — the inner denial produces outward moral collapse. Paul quotes vv.1-3 (with additions from Pss 5 and 140) in Rom 3:10-12 to establish universal sinfulness.</p>",
"2": "<p><strong>YHWH miššāmayim hišqîp ʿal-bĕnê ʾādām</strong> (<em>YHWH miššāmayim hišqîp ʿal-bĕnê ʾāḏām</em>): 'The LORD looks down from heaven on the children of man.' The hiphil hišqîp ('to look down, peer over') places YHWH at elevated vantage — an anthropomorphism for omniscience. The purpose: lirʾôt hăyēš maśkîl dōrēš ʾet-ʾĕlōhîm, 'to see if there are any who understand, who seek after God.' The participle maśkîl (from śākal, 'to have insight/wisdom') describes someone who grasps reality rightly — the opposite of the nābāl. The divine investigation sets up the devastating verdict of v.3.</p>",
"3": "<p><strong>hakkōl sār yaḥdāw neʾĕlāḥû</strong> (<em>hakkōl sār yaḥḏāw neʾĕlāḥû</em>): 'They have all turned aside; together they have become corrupt.' The all-inclusive hakkōl ('all') and yaḥdāw ('together') close every exit: there is no exception. The niphal neʾĕlāḥû ('become sour/corrupt') uses a term related to fermented milk that has turned — the image is of thoroughgoing contamination. Paul's citation in Rom 3:12-18 extends this to add quotations from Psalms 5, 140, and Isaiah 59, building a catena of human sinfulness — all humanity, Jew and Gentile, stands condemned before the bar of the law.</p>",
"4": "<p><strong>hălōʾ yādĕʿû kol-pōʿălê ʾāwen</strong> (<em>hălōʾ yāḏĕʿû kol-pōʿălê ʾāwen</em>): 'Have they no knowledge, all the evildoers?' The rhetorical question expresses shocked incomprehension. The phrase ʾōkĕlê ʿammî ʾāklû leḥem, 'they eat up my people as they eat bread,' uses the image of consuming bread — casual, daily, without moral awareness — to describe the exploitation of the ʿam ('people') by the pōʿălê ʾāwen ('workers of iniquity'). The additional indictment wĕʾet-YHWH lōʾ qārāʾû, 'and they do not call upon the LORD,' is the cultic symptom of the practical atheism declared in v.1.</p>",
"5": "<p><strong>šām pāḥădû pāḥad</strong> (<em>šām pāḥăḏû pāḥaḏ</em>): 'There they were in great terror.' The cognate accusative pāḥădû pāḥad ('they feared fear') is intensive — overwhelming dread. The phrase kî ʾĕlōhîm bĕdôr ṣaddîq, 'for God is with the generation of the righteous,' reveals the source of the wicked's terror: they discover that the God they denied (v.1) is actually present, defending the righteous (ṣaddîq) they were exploiting. The reversal echoes the Psalter's pervasive theme: the practical atheist who lives as though God does not see is surprised by the reality of divine presence.</p>",
"6": "<p><strong>ʿăṣat ʿānî tābîšû</strong> (<em>ʿăṣaṯ ʿānî ṯāḇîšû</em>): 'You would shame the plans of the poor.' The verb bôš ('shame, humiliate') in the hiphil tābîšû describes the wicked's attempt to undermine the counsel of the ʿānî ('poor, afflicted'). The response: kî YHWH maḥsēhû, 'because the LORD is his refuge.' The word maḥseh ('refuge, shelter') from ḥāsâ ('take refuge') — the same root as Ps 11:1 — positions YHWH as the answer to the wicked's attack on the poor. What the wicked do not reckon with is that their victim has a protector they cannot see.</p>",
"7": "<p><strong>mî yittēn miṣṣiyyôn yĕšûʿat yiśrāʾēl</strong> (<em>mî yittēn miṣṣiyyôn yĕšûʿaṯ yiśrāʾēl</em>): 'Oh that salvation for Israel would come out of Zion!' The exclamatory mî yittēn ('who will give? / oh that!') shifts from individual crisis to national hope. The phrase bĕšûb YHWH šĕbût ʿammô, 'when the LORD restores the fortunes of his people,' uses šûb šĕbût — an idiom for comprehensive restoration (used also in Jer 30:18; Job 42:10). This verse transforms the psalm from individual lament about fools to communal hope: the deliverance from practical atheism at every level — personal and national — issues from Zion, the place of divine kingship.</p>"
},
"15": {
"1": "<p><strong>YHWH mî-yāgûr bĕʾohŏlekā</strong> (<em>YHWH mî-yāḡûr bĕʾohŏleḵā</em>): 'O LORD, who shall sojourn in your tent?' Psalm 15 is a torah-liturgy or entrance psalm — an answer to the question posed at the sanctuary gate, identifying who may enter to worship. The noun ʾōhel ('tent') recalls the wilderness tabernacle and its successor at Jerusalem; har qodšekā ('your holy hill') is Zion/Mount Moriah. The double question — who may sojourn (gûr, temporary residence), who may dwell (šākan, settled habitation) — parallels Ps 24:3 ('who shall ascend the hill of the LORD?'). The answer is not ethnic or ritual but ethical.</p>",
"2": "<p><strong>hôlēk tāmîm ûpōʿēl ṣedeq</strong> (<em>hôlēḵ tāmîm ûp̄ōʿēl ṣeḏeq</em>): 'He who walks blamelessly and does what is right.' The present participles — hôlēk ('one who walks'), pōʿēl ('one who does'), dōbēr ('one who speaks') — describe character as persistent disposition rather than isolated acts. The noun tāmîm ('blameless, complete, without defect') is used of sacrificial animals without blemish (Lev 1:3) and of Noah (Gen 6:9) and Abraham (Gen 17:1) — moral completeness. The phrase wĕdōbēr ʾĕmet bĕlibābô, 'who speaks truth in his heart,' combines speech and interiority: the truthful person does not merely say true things but thinks truly.</p>",
"3": "<p><strong>lōʾ-rāgal ʿal-lĕšōnô</strong> (<em>lōʾ-rāḡal ʿal-lĕšōnô</em>): 'who does not slander with his tongue.' The verb rāgal ('to spy, go as a foot-soldier') in the piel means 'to slander, go about as a tale-bearer' — the image of someone who covertly undermines others. Three negatives characterize the qualified worshipper: no slander, no evil done to a neighbor, no reproach taken up against a friend. The phrase lōʾ nāśāʾ ḥerpâ ʿal-qĕrôbô ('does not take up a reproach against his neighbor') suggests not repeating or amplifying rumors about those close to him.</p>",
"4": "<p><strong>nibzeh bĕʿênāyw nimʾās</strong> (<em>niḇzeh bĕʿênāyw nimʾās</em>): 'in whose eyes a vile person is despised.' The niphal nibzeh ('despised, held in contempt') and nimʾās ('rejected, disdained') — the righteous person's moral perception correctly evaluates character rather than status. The contrast: wĕʾet-yirʾê YHWH yĕkabbēd, 'but he honors those who fear the LORD.' Moral evaluation follows theological reality, not social prestige. The crucial phrase: nišbaʿ lĕhāraʿ wĕlōʾ yāmîr, 'who swears to his own hurt and does not change.' The righteous person keeps an oath even when it costs him — the ultimate test of verbal integrity (cf. Matt 5:37).</p>",
"5": "<p><strong>kaspô lōʾ nātan bĕnešek</strong> (<em>ḵaspô lōʾ nāṯan bĕnešeḵ</em>): 'who does not put out his money at interest.' The noun nešek ('interest, biting') from nāšak ('to bite') describes usury — taking a bite from the poor through compound interest. The combination of nešek and tarbît ('increase') in Lev 25:36-37 was explicitly prohibited in lending to the poor within Israel. The final clause: wĕšōḥad ʿal-nāqî lōʾ lāqaḥ, 'who does not take a bribe against the innocent.' The word šōḥad ('bribe') is the corruption of the justice system that should protect the nāqî ('innocent'). The closing promise — ʿōśēh ʾēlleh lōʾ yimmôṭ lĕʿôlām, 'the one who does these things shall never be moved' — echoes lōʾ yimmôṭ of Ps 13:4 (the enemy's boast), now granted to the covenant-faithful as divine assurance.</p>"
},
"16": {
"1": "<p><strong>šomrēnî ʾēl kî ḥāsîtî bāk</strong> (<em>šomrēnî ʾēl kî ḥāsîṯî ḇāḵ</em>): 'Preserve me, O God, for I take refuge in you.' The miktam superscription (miktam lĕdāwid) is of uncertain meaning — possibly 'inscription' or related to ketam ('gold'), suggesting a precious composition. The qal imperative šomrēnî ('guard, keep, preserve') from šāmar invokes the divine watchfulness that is YHWH's primary covenant function (Num 6:24; Ps 121:7-8). The ground kî ḥāsîtî bāk ('because I have taken refuge in you') — the ḥāsâ root — places the psalmist entirely on YHWH's protective provision rather than any alternative.</p>",
"2": "<p><strong>ʾāmart laYHWH ʾădōnāy ʾātâ</strong> (<em>ʾāmartî laYHWH ʾăḏōnāy ʾāttâ</em>): 'I say to the LORD, 'You are my Lord.'' The confession ʾădōnāy ʾātâ ('you are my Lord/Master') is the foundational sovereignty declaration. The phrase ṭôbātî bal-ʿālêkā, 'my good is not beyond you / my good has no reference point above you,' affirms that all genuine blessing is located in and derived from YHWH. LXX renders this with some difficulty; the MT is also textually challenging. But the theological point is clear: YHWH is the psalmist's supreme good, not a means to other goods.</p>",
"3": "<p><strong>liqdōšîm ʾăšer bāʾāreṣ hēmmâ</strong> (<em>liqḏôšîm ʾăšer-bāʾāreṣ hēmmâ</em>): 'As for the holy ones in the land, they are the excellent ones.' The referent of qĕdôšîm ('holy ones') is debated: foreign gods/their devotees, or faithful Israelites. The following phrase wĕʾaddîrê kol-ḥepṣî bām ('and the noble/majestic ones, all my delight is in them') and v.4's contrast with those who 'run after another' suggests the qĕdôšîm here are the faithful covenant community. The psalmist's delight is with this community — a social theology of belonging to the people of YHWH.</p>",
"4": "<p><strong>yirbû ʿaṣṣĕbôtām ʾaḥēr māhārû</strong> (<em>yirbû ʿaṣṣĕḇôṯām ʾaḥēr māhārû</em>): 'The sorrows of those who run after another god shall multiply.' The noun ʿaṣṣābôt ('sorrows, idols') — related to ʿeṣeb ('pain/idol') — captures the double meaning: idol worship produces pain. The phrase ʾaḥēr māhārû, 'they run after another,' uses ʾaḥēr ('another') for foreign deities — a pejorative, refusing them divine titles. The psalmist's triple refusal — no drink offerings of blood, no taking their names on his lips, no offering — constitutes comprehensive rejection of the rival cult.</p>",
"5": "<p><strong>YHWH mĕnat-ḥelqî wĕkôsî</strong> (<em>YHWH mĕnaṯ-ḥelqî wĕḵôsî</em>): 'The LORD is my chosen portion and my cup.' The nouns ḥēleq ('portion, allotment') and kôs ('cup') together describe the totality of inheritance. In the land distribution (Josh 13-21), each tribe received a ḥēleq; Levi's portion was YHWH himself (Deut 10:9; 18:2). By claiming YHWH as his ḥēleq, the psalmist spiritualizes the levitical ideal: anyone may choose YHWH as the substance of their inheritance. The phrase ʾattâ tômîk gôrālî, 'you hold my lot,' pictures YHWH himself holding the lot-cast that determines the psalmist's future.</p>",
"6": "<p><strong>ḥăbālîm nāplû-lî binnĕʿīmîm</strong> (<em>ḥăḇālîm nāplû-lî ḇannĕʿîmîm</em>): 'The lines have fallen for me in pleasant places.' The noun ḥebel ('measuring line') refers to land surveying — the lines marking one's lot. The passive nāplû ('have fallen') is the language of lot-casting: the result of throwing the lot is that his portion lies in pleasant territory. The phrase ʾap-naḥălat šāpĕrâ ʿālay, 'indeed, I have a beautiful inheritance,' uses the rare verb šāpar ('to be beautiful/fair'). When YHWH is one's portion (v.5), the inheritance is inherently beautiful — the psalm's meditation on contentment grounded in divine choice.</p>",
"7": "<p><strong>ʾăbārēk ʾet-YHWH ʾăšer yĕʿāṣānî</strong> (<em>ʾăḇārēḵ ʾeṯ-YHWH ʾăšer yĕʿāṣānî</em>): 'I bless the LORD who gives me counsel.' The verb yāʿaṣ ('to counsel, advise') describes YHWH as the psalmist's wisdom-source. The phrase ʾap-lêlôt yissĕrûnî kilĕyôtāy, 'even in the night my kidneys (reins) instruct me,' attributes the body's night-time processing to divine instruction: the kidneys (kĕlāyôt), understood in Hebrew thought as the seat of deep feeling and moral intuition, function as an inner voice that continues YHWH's counsel in sleep. This nocturnal instruction anticipates the 'meditation day and night' of Ps 1:2.</p>",
"8": "<p><strong>šiwwîtî YHWH lĕnegdî tāmîd</strong> (<em>šiwwîṯî YHWH lĕneḡḏî ṯāmîd</em>): 'I have set the LORD always before me.' The verb šāwâ ('to set, place') in the piel šiwwîtî means 'I have placed/levelled before me as a standard.' The phrase kî mimînî bal-ʾemmôṭ, 'because he is at my right hand, I shall not be moved,' positions YHWH as the constant companion who prevents collapse. Peter cites vv.8-11 in Acts 2:25-28, arguing that David — who wrote this — did not die permanently (Acts 2:29), therefore the psalm speaks of the Messiah: Jesus who was raised from the dead is the true referent of the one who would not be moved.</p>",
"9": "<p><strong>lākēn śāmaḥ libbî wayyāgel kĕbôdî</strong> (<em>lāḵēn śāmaḥ libbî wayyāḡel kĕḇôḏî</em>): 'Therefore my heart is glad, and my glory rejoices.' The causal lākēn ('therefore') links the settled trust of v.8 to the threefold joy: heart (lēb), glory/honor (kābôd), and flesh (bāśār). The phrase ʾap-bĕśārî yiškon lābeṭaḥ, 'my flesh also rests in security,' is programmatic for Acts 2:26: Peter reads the resting of flesh in security as pointing beyond David's own confidence to the resurrection body of the Messiah — flesh that genuinely rested in the security of incorruption.</p>",
"10": "<p><strong>kî lōʾ-taʿăzōb napšî lišĕʾôl</strong> (<em>kî lōʾ-taʿăzōḇ napšî lišĕʾôl</em>): 'For you will not abandon my soul to Sheol.' The key word napšî ('my soul/life') — the whole self — will not be abandoned (ʿāzab) to Sheol (the realm of the dead). The parallelism: lōʾ-tittēn ḥăsîdĕkā lirʾôt šāḥat, 'nor will you give your Holy One to see the Pit.' The noun šāḥat ('pit, destruction') is parallel to Sheol. Peter's argument in Acts 2:27 is precise: since David died and his tomb is known (Acts 2:29), David could not have spoken of himself. The one who did not see corruption is Jesus, raised before his body could decay. Paul makes the same argument in Acts 13:35-37.</p>",
"11": "<p><strong>tôdîʿēnî ʾōraḥ ḥayyîm</strong> (<em>tôḏîʿēnî ʾōraḥ ḥayyîm</em>): 'You make known to me the path of life.' The hiphil tôdîʿēnî ('you cause me to know') from yādaʿ signals experiential, relational knowledge — not merely information about life but being shown its path. The phrase śōbaʿ śĕmāḥôt ʾet-pānêkā, 'fullness of joys with your face,' places the highest joy in the divine presence (pānêkā, 'your face'). The final phrase nĕʿīmôt bîmînĕkā nĕṣaḥ, 'pleasures at your right hand forevermore,' uses nĕṣaḥ ('forever') — the same word used of divine permanence in Ps 9:7. The path of life leads to perpetual divine presence: this verse grounds Christian eschatology in the Psalter's vision of beatific communion with YHWH.</p>"
},
"17": {
"1": "<p><strong>šimʿâ YHWH ṣedeq haqšîbâ rinnātî</strong> (<em>šimʿâ YHWH ṣedeq haqšîbâ rinnātî</em>): 'Hear a just cause, O LORD; attend to my cry.' Psalm 17 is a ṭĕpillâ ('prayer') — one of only five psalms so labeled (cf. Pss 86, 90, 102, 142). The opening appeal to ṣedeq ('righteousness/justice') frames the prayer as a legal appeal: the psalmist presents his case before the divine judge. The phrase bĕlōʾ śiptê mirmâ, 'from lips free of deceit,' establishes the speaker's credibility — this is not manipulation but genuine appeal. The term rinnâ ('cry, ringing cry') captures the emotional intensity of the plea.</p>",
"2": "<p><strong>millĕpānêkā mišpāṭî yēṣēʾ</strong> (<em>millĕp̄āneḵā mišpāṭî yēṣēʾ</em>): 'Let my vindication come from your presence.' The noun mišpāṭ ('judgment, vindication, sentence') is what the psalmist awaits from the divine court. The phrase ʿênêkā tiḥzenâ mêšārîm, 'let your eyes see what is right,' invites YHWH's direct judicial inspection. The use of millĕpānêkā ('from before your face') — divine presence as the source of the verdict — anticipates the beatific conclusion of v.15 where the psalmist will see that same face in righteousness.</p>",
"3": "<p><strong>bāḥantā libbî pāqadtā lāylâ</strong> (<em>ḇāḥantā libbî pāqaḏtā lāylâ</em>): 'You have tested my heart; you have visited me by night.' The two verbs — bāḥan ('test, examine,' the metallurgical term from Ps 11:4-5) and pāqad ('visit, muster, examine') — describe thorough divine investigation. The test occurs lāylâ ('by night') — when the psalmist is most vulnerable, most unguarded, most truly himself. The result: ṣĕraptanî bal-timṣāʾ, 'you have refined me; you found nothing.' The psalmist is not claiming sinlessness but innocence in the specific matter of the prayer — his hands are not contaminated by the enemy's violence.</p>",
"4": "<p><strong>lĕpĕʿullôt ʾādām bidbar śĕpātêkā</strong> (<em>lipĕʿullôṯ ʾāḏām biḏḇar śĕp̄āṯeḵā</em>): 'Regarding the works of man, by the word of your lips.' The phrase biḏbar śĕp̄āṯeḵā ('by the word of your lips') identifies YHWH's revealed word as the standard of behavior. The clause ʾănî šāmartî ʾōrĕḥôt pārîṣ, 'I have guarded myself from the paths of the violent,' uses pārîṣ ('violent one, destroyer') — the same social category as the enemy psalms describe. The claim is not moral perfectionism but covenant integrity: the psalmist has not followed the way of violence.</p>",
"5": "<p><strong>tāmōk ʾăšûray bĕmaʿglôtêkā</strong> (<em>ṯāmōk ʾăšûray bĕmaʿgĕlôṯeḵā</em>): 'My steps have held fast to your paths.' The phrase bal-nāmôṭû pĕʿāmāy, 'my feet have not slipped,' uses the same root môṭ ('to waver, slip') that appears in Ps 15:5 (the righteous 'shall not be moved') and Ps 13:4 (the enemy's boast). The psalmist's stability is attributed to divine holding (tāmōk, 'you hold firm') — not self-generated virtue but YHWH's grip on him as he walks in covenant paths.</p>",
"6": "<p><strong>ʾănî qĕrāʾtîkā kî-taʿănēnî ʾēl</strong> (<em>ʾănî qĕrāʾṯîḵā ḵî-ṯaʿănēnî ʾēl</em>): 'I call upon you, for you will answer me, O God.' The perfect qĕrāʾtî ('I have called') paired with the imperfect taʿănēnî ('you will answer') creates a confidence structure: past invocation grounds future expectation. The phrase haṭ-ʾoznĕkā lî šmaʿ ʾimrātî, 'incline your ear to me; hear my speech,' uses the anthropomorphism of a king bending close to hear a petition — personal, attentive, relational hearing.</p>",
"7": "<p><strong>haphlēʾ ḥăsādêkā môšîaʿ ḥôsîm</strong> (<em>haphlēʾ ḥăsāḏeḵā môšîaʿ ḥôsîm</em>): 'Show your marvelous steadfast love, O Savior of those who take refuge.' The hiphil haphlēʾ ('make wonderful/extraordinary') from pālāʾ ('to be marvelous') calls for ḥesed that exceeds ordinary expectation. The divine title môšîaʿ ḥôsîm, 'savior of those who take refuge,' combines the verb yāšaʿ ('save') with ḥāsâ ('take refuge') — matching the psalm's opening self-description as one who relies on YHWH. The phrase mimmitqômĕmîm bîmînekā, 'from those who rise up against your right hand,' places the enemies in opposition to divine power.</p>",
"8": "<p><strong>šomrēnî kĕʾîšôn bat-ʿāyin</strong> (<em>šomrēnî kĕʾîšôn baṯ-ʿāyin</em>): 'Keep me as the apple of the eye.' The phrase ʾîšôn bat-ʿāyin ('apple of the daughter of the eye') — the pupil — is the most tender image of intimate protection: the tiny, precious, reflexively guarded part of the body. The second image, bĕṣēl kĕnāpêkā tastîrēnî, 'hide me in the shadow of your wings,' draws on the protective imagery of a mother bird shielding her chicks (Deut 32:11; Ruth 2:12; Matt 23:37). Together, the two images — the guarded eye and the sheltering wing — express total, personal, enveloping protection.</p>",
"9": "<p><strong>mippĕnê rĕšāʿîm zû šaddûnî</strong> (<em>mippĕnê rĕšāʿîm zû šaddûnî</em>): 'from the wicked who do me violence.' The relative clause zû šaddûnî ('who destroy/deal violently with me') uses the root šādad ('to ruin, deal violently') — a characteristic activity of the wicked in the Psalter. The phrase ʾōyĕbay bĕnepeš yaqqîpû ʿālay, 'my deadly enemies surround me' — literally 'enemies against my soul/life who encircle me' — uses the napšî construction to indicate mortal enmity, not merely personal hostility.</p>",
"10": "<p><strong>ḥelbāmô sāgĕrû pîmô dibbĕrû bĕgēʾût</strong> (<em>ḥelbāmô sāgĕrû pîmô dibbĕrû ḇĕḡēʾûṯ</em>): 'They have closed their hearts; with their mouths they speak arrogantly.' The phrase ḥelbāmô sāgĕrû — literally 'their fat they have closed' — uses ḥeleb ('fat') as a metaphor for calloused insensitivity (cf. Ps 119:70: 'their heart is fat as grease'). The noun gēʾût ('pride, arrogance') describes the content of their speech. The psalmist characterizes the enemy by two failures: a closed heart that cannot receive correction and an arrogant mouth that overreaches all limits.</p>",
"11": "<p><strong>ʾašûrênû ʿattâ sĕbābûnû</strong> (<em>ʾašûrênû ʿattâ sĕḇāḇûnû</em>): 'In our steps they now surround us.' The plural surreptitiously shifts from 'me' (the individual psalmist) to 'us' — the community of the righteous who share this threat. The phrase ʿênêhem yāšîtû liṭṭôt bāʾāreṣ, 'they set their eyes to cast down to the ground,' describes the enemy's fixed gaze directed at bringing the righteous to earth — the same spatial language of exaltation and humiliation that runs through Psalms 9-10.</p>",
"12": "<p><strong>dimmyōnô kĕʾaryēh yiksopu litrup</strong> (<em>dimmyōnô kĕʾaryēh yiḵsôp liṭrôp</em>): 'He is like a lion eager to tear.' The simile kĕʾaryēh ('like a lion') returns from Ps 10:9 — the predator imagery for the wicked reaches its intensity here: not merely lurking but eager (yiksopu, 'yearns, longs') for prey. The parallel wĕkĕkĕpîr yōšēb bĕmistārîm, 'like a young lion crouching in ambush,' adds the youth-lion (kĕpîr) — strong and fierce. The two images — mature lion's desire and young lion's ambush — combine appetite with strategy.</p>",
"13": "<p><strong>qûmâ YHWH qaddĕmâh pānāyw</strong> (<em>qûmâ YHWH qaḏḏĕmâ p̄ānāyw</em>): 'Arise, O LORD! Confront him, cause him to bow.' The imperative qûmâ ('arise!') is the liturgical summons to divine action (cf. Ps 9:19; 10:12). The hiphil hakriʿēhû, 'cause him to bow/subdue him,' requests decisive defeat. The phrase pallĕṭâ napšî mērāšāʿ ḥarbĕkā, 'deliver my soul from the wicked by your sword,' invokes divine weaponry — YHWH himself fighting as a warrior on behalf of the vulnerable. The phrase ḥarbĕkā ('your sword') is an instrument of covenant judgment.</p>",
"14": "<p><strong>mĕmētîm yādĕkā YHWH mĕmētîm miḥeled</strong> (<em>mĕmētîm yāḏĕḵā YHWH mĕmētîm miḥeled</em>): 'by your hand, O LORD, from men of the world.' The phrase mĕmētîm ('from the dead / from men who are dying') combined with miḥeled ('from this transient world') categorizes the enemies by their mortality — they belong to the perishable world order. The description of their prosperity — ḥelqām bĕḥayyîm ûṣĕpûnĕkā tĕmallēʾ biṭnām, 'whose portion is in this life and whose belly you fill with your treasure' — does not condemn wealth per se but identifies those whose satisfaction is entirely worldly: they have their reward here (cf. Luke 6:24). The phrase yiśbĕʿû bānîm wĕhinnîḥû yitrām lĕʿôlĕlêhem, 'they are satisfied with children, and they leave their abundance to their infants,' is ironic: the legacy the wicked leave is material, transient, destined to be inherited by those equally vulnerable to mortality.</p>",
"15": "<p><strong>ʾănî bĕṣedeq ʾeḥĕzeh pānêkā</strong> (<em>ʾănî bĕṣeḏeq ʾeḥĕzeh p̄āneḵā</em>): 'As for me, I shall behold your face in righteousness.' The emphatic ʾănî ('as for me') makes a final contrast to the worldly satisfied of v.14. The verb ḥāzâ ('to behold, see in a vision') carries visionary weight — not a casual glance but a face-to-face encounter. The phrase bĕhāqîṣ ʾeśbaʿ tĕmûnātekā, 'when I awake, I shall be satisfied with your likeness,' introduces the moment of waking — ʾāqîṣ (from qîṣ, 'to awake from sleep'). The word tĕmûnâ ('likeness, form, similitude') — the same word used in Num 12:8 for Moses seeing the form of YHWH — is the ultimate beatific vision. Whether the psalmist speaks of morning prayer, resurrection, or eschatological encounter, the hunger of Ps 17 reaches its resolution here: satisfaction comes not from the world's abundance but from the face of God.</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    total = sum(len(v) for v in PSALMS.values())
    print(f'Psalms 9-17 mkt-original written — {total} verses.')

if __name__ == '__main__': main()
